changeSet.sql:
drop trigger if exists trg_album_enforce_resource_id_immutable on gmdb.album;
create trigger trg_album_enforce_resource_id_immutable
    before update of details on gmdb.album
    for each row
    execute function gmdb.details_enforce_resource_id_immutable();

drop trigger if exists trg_album_default_resource_id on gmdb.album;
create trigger trg_album_default_resource_id
    before insert on gmdb.album
    for each row
    execute function gmdb.details_default_resource_id();
